 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→//// Convolution Functions
 26→
 27→void conv_dw_HWC_s8_s8_s8_sym_bias_any_chmult(const q7_t * in_tensor,
 28→        const uint16_t in_tensor_dim_x,
 29→        const uint16_t in_tensor_dim_y,
 30→        const uint16_t in_tensor_ch,
 31→        const q7_t * ker_weight,
 32→        const uint16_t out_tensor_ch,
 33→        const uint16_t ker_dim_x,
 34→        const uint16_t ker_dim_y,
 35→        const uint16_t pad_x,
 36→        const uint16_t pad_y,
 37→        const uint16_t stride_x,
 38→        const uint16_t stride_y,
 39→        const q31_t * bias,
 40→        const uint16_t pre_rshift,
 41→        const uint16_t out_scale,
 42→        const uint16_t post_rshift,
 43→        q7_t * out_tensor,
 44→        const uint16_t out_tensor_dim_x,
 45→        const uint16_t out_tensor_dim_y,
 46→        q15_t * in_tmp_buf)
 47→{
 48→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
 49→    int32_t ch_mult = out_tensor_ch / in_tensor_ch;
 50→
 51→    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
 52→    {
 53→        const int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
 54→        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
 55→        {
 56→            const int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
 57→            for (int32_t i_in_ch = 0; i_in_ch < in_tensor_ch; i_in_ch++)
 58→            {
 59→                int32_t i_ch_mult = 0;
 60→                long vl;
 61→                long ch_mult_rest = ch_mult;
 62→
 63→                for (; i_ch_mult < ch_mult; i_ch_mult+=vl)
 64→                {
 65→                    const int i_out_ch = i_ch_mult + i_in_ch * ch_mult;
 66→                    int32_t ker_y_start = MAX(0, -base_idx_y);
 67→                    int32_t ker_x_start = MAX(0, -base_idx_x);;
 68→                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);;
 69→                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
 70→
 71→                    q31_t * pBias = (q31_t *)&bias[i_out_ch];
 72→                    NDS_VEC_VSETVLI(vl, ch_mult_rest, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 73→                    NDS_VEC_VLE32_V(NDS_VEC_V0, pBias);
 74→
 75→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
 76→                    for (int i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
 77→                    {
 78→                        const int32_t i_y = base_idx_y + i_ker_y;
 79→                        for (int i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
 80→                        {
 81→                            const int32_t i_x = base_idx_x + i_ker_x;
 82→                            int32_t in_idx = (i_y * in_tensor_dim_x + i_x) * in_tensor_ch + i_in_ch;
 83→                            int32_t wt_idx = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + i_out_ch;
 84→
 85→                            q7_t in_val = in_tensor[in_idx];
 86→                            q7_t * wt_ptr = (q7_t *)&ker_weight[wt_idx];
 87→                            NDS_VEC_VLE8_V(NDS_VEC_V8, wt_ptr);
 88→                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, in_val, NDS_VEC_V8);
 89→                        }
 90→                    }
 91→
 92→                    q7_t * out_ptr = &out_tensor[(i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + i_out_ch];
 93→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 94→                    NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
 95→                    NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
 96→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
 97→                    NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
 98→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
 99→                    NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
100→                    NDS_VEC_VSE8_V(NDS_VEC_V0, out_ptr);
101→
102→                    ch_mult_rest -= vl;
103→                }
104→            }
105→        }
106→    }
107→#elif defined(ENA_DSP_ISA_64)
108→    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
109→    {
110→        const int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
111→        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
112→        {
113→            const int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
114→            for (int32_t i_in_ch = 0; i_in_ch < in_tensor_ch; i_in_ch++)
115→            {
116→                int32_t i_ch_mult = 0;
117→                int32_t ch_mult = out_tensor_ch / in_tensor_ch;
118→
119→                for (; (i_ch_mult + SIMD_NUM_Q7) <= ch_mult; i_ch_mult += SIMD_NUM_Q7)
120→                {
121→                    const int i_out_ch = i_ch_mult + i_in_ch * ch_mult;
122→                    int32_t ker_y_start = MAX(0, -base_idx_y);
123→                    int32_t ker_x_start = MAX(0, -base_idx_x);;
124→                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);;
125→                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
126→
127→                    long conv_out_0 = 0;
128→                    long conv_out_1 = 0;
129→                    long conv_out_2 = 0;
130→                    long conv_out_3 = 0;
131→                    long conv_out_4 = 0;
132→                    long conv_out_5 = 0;
133→                    long conv_out_6 = 0;
134→                    long conv_out_7 = 0;
135→
136→                    for (int i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
137→                    {
138→                        const int32_t i_y = base_idx_y + i_ker_y;
139→                        for (int i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
140→                        {
141→                            const int32_t i_x = base_idx_x + i_ker_x;
142→                            int32_t in_idx = (i_y * in_tensor_dim_x + i_x) * in_tensor_ch + i_in_ch;
143→                            int32_t wt_idx = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + i_out_ch;
144→
145→                            q31_t in_val = in_tensor[in_idx];
146→                            long in_val_q31x2 = NDS_DSP_PKBB32(in_val, in_val);
147→
148→                            q7_t * tmp_ptr = (q7_t *)&ker_weight[wt_idx];
149→                            long kernel_q7x8 = *__SIMD64(tmp_ptr);
150→                            long kernel_q15x4_0 = NDS_DSP_SUNPKD810(kernel_q7x8);
151→                            long kernel_q15x4_1 = NDS_DSP_SUNPKD832(kernel_q7x8);
152→
153→                            conv_out_0 = NDS_DSP_KMABB(conv_out_0, in_val_q31x2, kernel_q15x4_0);
154→                            conv_out_1 = NDS_DSP_KMABT(conv_out_1, in_val_q31x2, kernel_q15x4_0);
155→                            conv_out_2 = NDS_DSP_KMABB(conv_out_2, in_val_q31x2, kernel_q15x4_1);
156→                            conv_out_3 = NDS_DSP_KMABT(conv_out_3, in_val_q31x2, kernel_q15x4_1);
157→                        }
158→                    }
159→
160→                    conv_out_4 = conv_out_0 >> 32;
161→                    conv_out_5 = conv_out_1 >> 32;
162→                    conv_out_6 = conv_out_2 >> 32;
163→                    conv_out_7 = conv_out_3 >> 32;
164→                    conv_out_0 = (int32_t)conv_out_0;
165→                    conv_out_1 = (int32_t)conv_out_1;
166→                    conv_out_2 = (int32_t)conv_out_2;
167→                    conv_out_3 = (int32_t)conv_out_3;
168→
169→                    // add bias back
170→                    conv_out_0 += bias[i_out_ch];
171→                    conv_out_1 += bias[i_out_ch + 1];
172→                    conv_out_2 += bias[i_out_ch + 2];
173→                    conv_out_3 += bias[i_out_ch + 3];
174→                    conv_out_4 += bias[i_out_ch + 4];
175→                    conv_out_5 += bias[i_out_ch + 5];
176→                    conv_out_6 += bias[i_out_ch + 6];
177→                    conv_out_7 += bias[i_out_ch + 7];
178→
179→                    conv_out_0 = (conv_out_0 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
180→                    conv_out_1 = (conv_out_1 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
181→                    conv_out_2 = (conv_out_2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
182→                    conv_out_3 = (conv_out_3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
183→                    conv_out_4 = (conv_out_4 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
184→                    conv_out_5 = (conv_out_5 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
185→                    conv_out_6 = (conv_out_6 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
186→                    conv_out_7 = (conv_out_7 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
187→
188→                    int32_t i_out = (i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + i_out_ch;
189→                    out_tensor[i_out] = NDS_DSP_SATS((conv_out_0 >> post_rshift), 8);
190→                    out_tensor[i_out + 1] = NDS_DSP_SATS((conv_out_1 >> post_rshift), 8);
191→                    out_tensor[i_out + 2] = NDS_DSP_SATS((conv_out_2 >> post_rshift), 8);
192→                    out_tensor[i_out + 3] = NDS_DSP_SATS((conv_out_3 >> post_rshift), 8);
193→                    out_tensor[i_out + 4] = NDS_DSP_SATS((conv_out_4 >> post_rshift), 8);
194→                    out_tensor[i_out + 5] = NDS_DSP_SATS((conv_out_5 >> post_rshift), 8);
195→                    out_tensor[i_out + 6] = NDS_DSP_SATS((conv_out_6 >> post_rshift), 8);
196→                    out_tensor[i_out + 7] = NDS_DSP_SATS((conv_out_7 >> post_rshift), 8);
197→                }
198→
199→                for (; i_ch_mult < ch_mult; i_ch_mult++)
200→                {
201→                    const int i_out_ch = i_ch_mult + i_in_ch * ch_mult;
202→                    int32_t ker_y_start = MAX(0, -base_idx_y);
203→                    int32_t ker_x_start = MAX(0, -base_idx_x);;
204→                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);;
205→                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
206→
207→                    int32_t conv_out = bias[i_out_ch];
208→                    for (int i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
209→                    {
210→                        const int32_t i_y = base_idx_y + i_ker_y;
211→                        for (int i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
212→                        {
213→                            const int32_t i_x = base_idx_x + i_ker_x;
214→                            int32_t in_idx = (i_y * in_tensor_dim_x + i_x) * in_tensor_ch + i_in_ch;
215→                            int32_t wt_idx = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + i_out_ch;
216→
217→                            conv_out += in_tensor[in_idx] * ker_weight[wt_idx];
218→                        }
219→                    }
220→
221→                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
222→                    out_tensor[(i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + i_out_ch] = NDS_DSP_SATS((conv_out >> post_rshift), 8);
223→                }
224→            }
225→        }
226→    }
227→#elif defined(ENA_DSP_ISA)
228→    for (int32_t i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
229→    {
230→        const int32_t base_idx_y = (i_out_y * stride_y) - pad_y;
231→        for (int32_t i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
232→        {
233→            const int32_t base_idx_x = (i_out_x * stride_x) - pad_x;
234→            for (int32_t i_in_ch = 0; i_in_ch < in_tensor_ch; i_in_ch++)
235→            {
236→                int32_t i_ch_mult = 0;
237→                int32_t ch_mult = out_tensor_ch / in_tensor_ch;
238→
239→                for (; (i_ch_mult + SIMD_NUM_Q7) <= ch_mult; i_ch_mult += SIMD_NUM_Q7)
240→                {
241→                    const int i_out_ch = i_ch_mult + i_in_ch * ch_mult;
242→                    int32_t ker_y_start = MAX(0, -base_idx_y);
243→                    int32_t ker_x_start = MAX(0, -base_idx_x);;
244→                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);;
245→                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
246→
247→                    int32_t conv_out_0 = bias[i_out_ch];
248→                    int32_t conv_out_1 = bias[i_out_ch + 1];
249→                    int32_t conv_out_2 = bias[i_out_ch + 2];
250→                    int32_t conv_out_3 = bias[i_out_ch + 3];
251→
252→                    for (int i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
253→                    {
254→                        const int32_t i_y = base_idx_y + i_ker_y;
255→                        for (int i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
256→                        {
257→                            const int32_t i_x = base_idx_x + i_ker_x;
258→                            int32_t in_idx = (i_y * in_tensor_dim_x + i_x) * in_tensor_ch + i_in_ch;
259→                            int32_t wt_idx = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + i_out_ch;
260→
261→                            q31_t in_val = in_tensor[in_idx];
262→                            q7_t * tmp_ptr = (q7_t *)&ker_weight[wt_idx];
263→                            q31_t kernel_q7x4 = *__SIMD32(tmp_ptr);
264→                            q31_t kernel_q15x2_1 = NDS_DSP_SUNPKD820(kernel_q7x4);
265→                            q31_t kernel_q15x2_2 = NDS_DSP_SUNPKD831(kernel_q7x4);
266→
267→                            conv_out_0 = NDS_DSP_KMABB(conv_out_0, in_val, kernel_q15x2_1);
268→                            conv_out_1 = NDS_DSP_KMABB(conv_out_1, in_val, kernel_q15x2_2);
269→                            conv_out_2 = NDS_DSP_KMABT(conv_out_2, in_val, kernel_q15x2_1);
270→                            conv_out_3 = NDS_DSP_KMABT(conv_out_3, in_val, kernel_q15x2_2);
271→                        }
272→                    }
273→
274→                    conv_out_0 = (conv_out_0 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
275→                    conv_out_1 = (conv_out_1 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
276→                    conv_out_2 = (conv_out_2 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
277→                    conv_out_3 = (conv_out_3 >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
278→
279→                    int32_t i_out = (i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + i_out_ch;
280→                    out_tensor[i_out] = NDS_DSP_SATS((conv_out_0 >> post_rshift), 8);
281→                    out_tensor[i_out + 1] = NDS_DSP_SATS((conv_out_1 >> post_rshift), 8);
282→                    out_tensor[i_out + 2] = NDS_DSP_SATS((conv_out_2 >> post_rshift), 8);
283→                    out_tensor[i_out + 3] = NDS_DSP_SATS((conv_out_3 >> post_rshift), 8);
284→                }
285→
286→                for (; i_ch_mult < ch_mult; i_ch_mult++)
287→                {
288→                    const int i_out_ch = i_ch_mult + i_in_ch * ch_mult;
289→                    int32_t ker_y_start = MAX(0, -base_idx_y);
290→                    int32_t ker_x_start = MAX(0, -base_idx_x);;
291→                    int32_t ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);;
292→                    int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);
293→
294→                    int32_t conv_out = bias[i_out_ch];
295→                    for (int i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
296→                    {
297→                        const int32_t i_y = base_idx_y + i_ker_y;
298→                        for (int i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
299→                        {
300→                            const int32_t i_x = base_idx_x + i_ker_x;
301→                            int32_t in_idx = (i_y * in_tensor_dim_x + i_x) * in_tensor_ch + i_in_ch;
302→                            int32_t wt_idx = (i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + i_out_ch;
303→
304→                            conv_out += in_tensor[in_idx] * ker_weight[wt_idx];
305→                        }
306→                    }
307→
308→                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
309→                    out_tensor[(i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + i_out_ch] = NDS_DSP_SATS((conv_out >> post_rshift), 8);
310→                }
311→            }
312→        }
313→    }
314→#else
315→    int i_out_y, i_out_x, i_ch_in, i_ch_mult;
316→    int i_ker_y, i_ker_x;
317→    int ch_mult = out_tensor_ch / in_tensor_ch;
318→
319→    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
320→    {
321→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
322→        {
323→            for (i_ch_in = 0; i_ch_in < in_tensor_ch; i_ch_in++)
324→            {
325→                for (i_ch_mult = 0; i_ch_mult < ch_mult; i_ch_mult++)
326→                {
327→                    const int idx_out_ch = i_ch_mult + i_ch_in * ch_mult;
328→                    int conv_out = bias[idx_out_ch];
329→                    for (i_ker_y = 0; i_ker_y < ker_dim_y; i_ker_y++)
330→                    {
331→                        for (i_ker_x = 0; i_ker_x < ker_dim_x; i_ker_x++)
332→                        {
333→                            int in_row = stride_y * i_out_y + i_ker_y - pad_y;
334→                            int in_col = stride_x * i_out_x + i_ker_x - pad_x;
335→                            if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
336→                            {
337→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + i_ch_in] *
338→                                            ker_weight[(i_ker_y * ker_dim_x + i_ker_x) * (in_tensor_ch * ch_mult) + idx_out_ch];
339→                            }
340→                        }
341→                    }
342→                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
343→                    out_tensor[(i_out_y * out_tensor_dim_x + i_out_x) * out_tensor_ch + idx_out_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
344→                }
345→            }
346→        }
347→    }
348→#endif
349→}
350→
351→void conv_dw_HWC_s8_s8_s8_sym_bias_any(const q7_t * in_tensor,
352→        const uint16_t in_tensor_dim_x,
353→        const uint16_t in_tensor_dim_y,
354→        const uint16_t in_tensor_ch,
355→        const q7_t * ker_weight,
356→        const uint16_t out_tensor_ch,
357→        const uint16_t ker_dim_x,
358→        const uint16_t ker_dim_y,
359→        const uint16_t pad_x,
360→        const uint16_t pad_y,
361→        const uint16_t stride_x,
362→        const uint16_t stride_y,
363→        const q31_t * bias,
364→        const uint16_t pre_rshift,
365→        const uint16_t out_scale,
366→        const uint16_t post_rshift,
367→        q7_t * out_tensor,
