input.old_string:
NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
for(long ker_y = ker_y_start; ker_y < MIN(ker_dim_y, in_tensor_dim_y - in_y); ++ker_y)
{
    q7_t *input_ptr2  = (q7_t*)input_ptr;
    q7_t *kernel_ptr2 = (q7_t*)kernel_ptr;

    for(long ker_x = ker_x_start; ker_x < MIN(ker_dim_x, in_tensor_dim_x - in_x); ++ker_x)
    {
        NDS_VEC_VLE8_V(NDS_VEC_V8, input_ptr2);
        NDS_VEC_VLE8_V(NDS_VEC_V10, kernel_ptr2);
        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V10, NDS_VEC_V8);
        input_ptr2 += in_tensor_ch;
        kernel_ptr2 += in_tensor_ch;
    }

    input_ptr  += (in_tensor_ch * in_tensor_dim_x);
    kernel_ptr += (in_tensor_ch * ker_dim_x);
}

input.new_string:
NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
long ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - in_y);
long ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - in_x);
long ker_x_count = ker_x_end - ker_x_start;
for(long ker_y = ker_y_start; ker_y < ker_y_end; ++ker_y)
{
    q7_t *input_ptr2  = (q7_t*)input_ptr;
    q7_t *kernel_ptr2 = (q7_t*)kernel_ptr;

    long ker_x = 0;
    // Unrolled loop: process 2 kernel x positions per iteration
    for(; ker_x + 1 < ker_x_count; ker_x += 2)
    {
        NDS_VEC_VLE8_V(NDS_VEC_V8, input_ptr2);
        NDS_VEC_VLE8_V(NDS_VEC_V10, kernel_ptr2);
        input_ptr2 += in_tensor_ch;
        kernel_ptr2 += in_tensor_ch;
        NDS_VEC_VLE8_V(NDS_VEC_V12, input_ptr2);
        NDS_VEC_VLE8_V(NDS_VEC_V14, kernel_ptr2);
        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V10, NDS_VEC_V8);
        input_ptr2 += in_tensor_ch;
        kernel_ptr2 += in_tensor_ch;
        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V14, NDS_VEC_V12);
    }
    // Handle remaining kernel x position
    if(ker_x < ker_x_count)
    {
        NDS_VEC_VLE8_V(NDS_VEC_V8, input_ptr2);
        NDS_VEC_VLE8_V(NDS_VEC_V10, kernel_ptr2);
        NDS_VEC_VQMACC_VV(NDS_VEC_V0, NDS_VEC_V10, NDS_VEC_V8);
    }

    input_ptr  += (in_tensor_ch * in_tensor_dim_x);
    kernel_ptr += (in_tensor_ch * ker_dim_x);
}
